    14→  --accent-2: #533483;
    15→  --text: #e0e0f0;
    16→  --text-muted: #8888aa;
    17→  --surface: rgba(255, 255, 255, 0.06);
    18→  --surface-hover: rgba(255, 255, 255, 0.10);
    19→  --border: rgba(255, 255, 255, 0.08);
    20→  --radius: 16px;
    21→  --radius-sm: 10px;
    22→  --transition: 0.2s ease;
    23→  --mic-size: 88px;
    24→  --ring-size: 128px;
    25→}
    26→
    27→html, body {
    28→  height: 100%;
    29→  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    30→  background: var(--bg);
    31→  color: var(--text);
    32→  -webkit-font-smoothing: antialiased;
    33→  -webkit-tap-highlight-color: transparent;
    34→  overscroll-behavior: none;
    35→}
    36→
    37→#app {
    38→  display: flex;
    39→  flex-direction: column;
    40→  height: 100dvh;
    41→  max-width: 480px;
