    70→  animation: pulse-dot 3s ease-in-out infinite;
    71→}
    72→
    73→@keyframes pulse-dot {
    74→  0%, 100% { opacity: 1; transform: scale(1); }
    75→  50% { opacity: 0.6; transform: scale(0.85); }
    76→}
    77→
    78→.header h1 {
    79→  font-size: 1.25rem;
    80→  font-weight: 700;
    81→  letter-spacing: 0.03em;
    82→  color: var(--text);
    83→}
    84→
    85→.icon-btn {
    86→  background: var(--surface);
    87→  border: 1px solid var(--border);
    88→  color: var(--text-muted);
    89→  border-radius: 50%;
    90→  width: 40px;
    91→  height: 40px;
    92→  display: flex;
    93→  align-items: center;
    94→  justify-content: center;
    95→  cursor: pointer;
    96→  transition: background var(--transition), color var(--transition);
    97→}
    98→
    99→.icon-btn svg {
   100→  width: 18px;
   101→  height: 18px;
   102→}
   103→
   104→.icon-btn:hover, .icon-btn:focus-visible {
   105→  background: var(--surface-hover);
   106→  color: var(--text);
   107→  outline: none;
   108→}
   109→
   110→/* ===== Messages ===== */
   111→.messages {
   112→  flex: 1;
   113→  overflow-y: auto;
   114→  padding: 12px 20px;
   115→  display: flex;
   116→  flex-direction: column;
   117→  gap: 10px;
   118→  -webkit-overflow-scrolling: touch;
   119→  scrollbar-width: thin;
   120→  scrollbar-color: var(--border) transparent;
   121→}
   122→
   123→.messages::-webkit-scrollbar {
   124→  width: 4px;
   125→}
   126→
   127→.messages::-webkit-scrollbar-track {
   128→  background: transparent;
   129→}
   130→
   131→.messages::-webkit-scrollbar-thumb {
   132→  background: var(--border);
   133→  border-radius: 2px;
   134→}
