/* ===== Reset & Base ===== */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg: #1a1a2e;
  --bg-2: #16213e;
  --bg-3: #0f3460;
  --accent: #e94560;
  --accent-glow: rgba(233, 69, 96, 0.4);
  --accent-2: #533483;
  --text: #e0e0f0;
  --text-muted: #8888aa;
  --surface: rgba(255, 255, 255, 0.06);
  --surface-hover: rgba(255, 255, 255, 0.10);
  --border: rgba(255, 255, 255, 0.08);
  --radius: 16px;
  --radius-sm: 10px;
  --transition: 0.2s ease;
  --mic-size: 88px;
  --ring-size: 128px;
}

html, body {
  height: 100%;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  overscroll-behavior: none;
}

#app {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  max-width: 480px;
  margin: 0 auto;
  position: relative;
}

/* ===== Header ===== */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 20px 12px;
  background: linear-gradient(180deg, var(--bg) 0%, transparent 100%);
  position: relative;
  z-index: 10;
  flex-shrink: 0;
}

.header-title {
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo-dot {
  width: 10px;
  height: 10px;
  background: var(--accent);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--accent-glow);
  animation: pulse-dot 3s ease-in-out infinite;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.6; transform: scale(0.85); }
}

.header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  letter-spacing: 0.03em;
  color: var(--text);
}

.icon-btn {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: 50%;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background var(--transition), color var(--transition);
}

.icon-btn svg {
  width: 18px;
  height: 18px;
}

.icon-btn:hover, .icon-btn:focus-visible {
  background: var(--surface-hover);
  color: var(--text);
  outline: none;
}

/* ===== Messages ===== */
.messages {
  flex: 1;
  overflow-y: auto;
  padding: 12px 20px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.messages::-webkit-scrollbar {
  width: 4px;
}

.messages::-webkit-scrollbar-track {
  background: transparent;
}

.messages::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 2px;
}

.messages-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.messages-empty p {
  color: var(--text-muted);
  font-size: 0.9rem;
  text-align: center;
}

/* Message bubble */
.message {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  border-bottom-right-radius: 4px;
  padding: 12px 16px;
  max-width: 100%;
  word-break: break-word;
  animation: slide-up 0.25s ease both;
}

.message.sending {
  opacity: 0.6;
}

.message.sent {
  border-color: rgba(233, 69, 96, 0.2);
}

.message.error {
  border-color: rgba(255, 80, 80, 0.3);
}

.message-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
}

.message-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 6px;
}

.message-time {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.message-status {
  font-size: 0.72rem;
  padding: 2px 7px;
  border-radius: 20px;
  background: var(--surface);
  color: var(--text-muted);
}

.message.sent .message-status {
  background: rgba(233, 69, 96, 0.15);
  color: var(--accent);
}

.message.error .message-status {
  background: rgba(255, 80, 80, 0.15);
  color: #ff6b6b;
}

@keyframes slide-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ===== Live Transcript ===== */
.live-transcript {
  margin: 0 20px 8px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  animation: fade-in 0.2s ease;
}

.live-transcript p {
  font-size: 0.92rem;
  color: var(--text-muted);
  font-style: italic;
  line-height: 1.5;
  min-height: 1.4em;
}

.live-transcript p.has-text {
  color: var(--text);
  font-style: normal;
}

/* ===== Transcript Bar (post-recording) ===== */
.transcript-bar {
  margin: 0 20px 12px;
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  animation: slide-up 0.2s ease;
}

.transcript-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
  margin-bottom: 14px;
  word-break: break-word;
}

.transcript-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ===== Buttons ===== */
.btn-ghost {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: var(--radius-sm);
  padding: 8px 18px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all var(--transition);
}

.btn-ghost:hover, .btn-ghost:focus-visible {
  background: var(--surface);
  color: var(--text);
  outline: none;
}

.btn-send {
  background: var(--accent);
  border: none;
  color: #fff;
  border-radius: var(--radius-sm);
  padding: 8px 22px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: all var(--transition);
  box-shadow: 0 2px 12px rgba(233, 69, 96, 0.35);
}

.btn-send:hover, .btn-send:focus-visible {
  background: #ff5c75;
  outline: none;
  box-shadow: 0 4px 20px rgba(233, 69, 96, 0.55);
}

/* ===== Mic Section ===== */
.mic-section {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 16px 20px 36px;
  gap: 16px;
}

.mic-hint {
  font-size: 0.85rem;
  color: var(--text-muted);
  letter-spacing: 0.04em;
  transition: color var(--transition);
}

.mic-hint.active {
  color: var(--accent);
}

/* Ring / glow around button */
.mic-ring {
  position: relative;
  width: var(--ring-size);
  height: var(--ring-size);
  display: flex;
  align-items: center;
  justify-content: center;
}

.mic-ring::before,
.mic-ring::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 2px solid transparent;
  transition: all 0.3s ease;
}

.mic-ring.recording::before {
  border-color: var(--accent-glow);
  animation: ring-pulse 1.4s ease-in-out infinite;
}

.mic-ring.recording::after {
  border-color: rgba(233, 69, 96, 0.15);
  animation: ring-pulse 1.4s ease-in-out 0.7s infinite;
}

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 1; }
  100% { transform: scale(1.6); opacity: 0; }
}

/* The mic button */
.mic-btn {
  position: relative;
  width: var(--mic-size);
  height: var(--mic-size);
  border-radius: 50%;
  border: none;
  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
  color: #fff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.08);
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  -webkit-user-select: none;
  user-select: none;
  touch-action: manipulation;
  z-index: 1;
}

.mic-btn:hover {
  transform: scale(1.05);
  box-shadow:
    0 6px 32px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(255, 255, 255, 0.12);
}

.mic-btn:active {
  transform: scale(0.96);
}

.mic-btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 4px;
}

.mic-btn.recording {
  background: linear-gradient(145deg, var(--accent), #c0392b);
  box-shadow:
    0 4px 32px var(--accent-glow),
    0 0 0 1px rgba(233, 69, 96, 0.3);
  animation: mic-glow 1.4s ease-in-out infinite alternate;
}

@keyframes mic-glow {
  from { box-shadow: 0 4px 24px var(--accent-glow), 0 0 0 1px rgba(233, 69, 96, 0.3); }
  to   { box-shadow: 0 4px 48px rgba(233, 69, 96, 0.7), 0 0 0 1px rgba(233, 69, 96, 0.5); }
}

.mic-icon {
  width: 36px;
  height: 36px;
  transition: transform var(--transition);
}

.mic-btn.recording .mic-icon {
  transform: scale(1.1);
}

